INSERT INTO public.questions VALUES ('04148a45-5f75-4337-9506-cd57c34c4346', '2233b1bc-2fdb-4d24-9641-80c114ebf715', 'checkbox', 'Questions 24–25', NULL, '<p data-start="610" data-end="637">Choose TWO correct answers.</p>
<h3 data-start="639" data-end="699">Who will Sylvia and Greg ask to take part in the survey?</h3>
', 'multiple_choice_many', 'null', '[{"option": "companies", "correct": false}, {"option": "lecturers", "correct": false}, {"option": "local residents", "correct": true}, {"option": "schoolchildren", "correct": false}, {"option": "university students", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('23bcbb96-848f-4bcf-bff3-81e59f948873', 'ee2dab1d-1d3f-4bfa-82f3-c036e621b93d', 'matrix', 'Questions 1-6.', NULL, '<p>Classify the following developments as characterising</p>
<p>Write the correct letter, A, B or C, in boxes 1-6 on your answer sheet</p>
', 'other', NULL, NULL, '{"layoutType": "standard", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "becoming interested in people of the other gender", "correctCategoryLetter": "B"}, {"itemText": "beginning to choose a future career", "correctCategoryLetter": "B"}, {"itemText": "needing to feel the same as one’s friends", "correctCategoryLetter": "A"}, {"itemText": "beginning to form a self-image separate from the family context", "correctCategoryLetter": "A"}, {"itemText": "having less need for the good opinion of friends", "correctCategoryLetter": "C"}, {"itemText": "exposing oneself to dangers", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "early adolescence", "categoryLetter": "A"}, {"categoryText": "middle adolescence", "categoryLetter": "B"}, {"categoryText": "late adolescence", "categoryLetter": "C"}]}', '[{"content": "<h3 data-path-to-node=\"4\">1. The period when the ability to think about abstract concepts increases significantly.</h3>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án:</strong> <strong>B (middle adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 3) “The growth in ability to deal with <strong>abstractions accelerates during the middle stages of adolescence</strong>.”</li>\n<li><strong>Giải thích:</strong> Khả năng xử lý các khái niệm trừu tượng tăng tốc mạnh mẽ nhất vào giai đoạn <strong>giữa</strong> của tuổi vị thành niên.</li>\n</ul>\n<h3 data-path-to-node=\"6\">2. The period when young people are most concerned about their physical appearance.</h3>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án:</strong> <strong>B (middle adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 2) “The effect of this rapid change is that <strong>mid-adolescents are body-conscious</strong>…”</li>\n<li><strong>Giải thích:</strong> Do sự thay đổi thể chất quá nhanh, trẻ ở giai đoạn <strong>giữa</strong> vị thành niên thường tự ý thức và quan tâm nhất đến vẻ ngoài/cơ thể mình.</li>\n</ul>\n<h3 data-path-to-node=\"8\">3. The period when risk-taking is considered a normal part of development.</h3>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án:</strong> <strong>B (middle adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 11) “…suggest that <strong>risk-taking may be a normal developmental process of middle adolescence</strong>.”</li>\n<li><strong>Giải thích:</strong> Bài đọc khẳng định hành vi mạo hiểm là một phần bình thường của quá trình phát triển ở giai đoạn <strong>giữa</strong>.</li>\n</ul>\n<h3 data-path-to-node=\"10\">4. The period when the need for approval from peers is at its highest.</h3>\n<ul data-path-to-node=\"11\">\n<li><strong>Đáp án:</strong> <strong>A (early adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 10) “…it seems to <strong>hit a peak of importance during early adolescence</strong>… Early adolescence is also a period of <strong>intense conformity to peers</strong>.”</li>\n<li><strong>Giải thích:</strong> Sự tương tác và nhu cầu được bạn bè chấp nhận/phê duyệt đạt đỉnh điểm quan trọng vào giai đoạn <strong>đầu</strong> vị thành niên.</li>\n</ul>\n<h3 data-path-to-node=\"12\">5. The period when young people begin to establish their own personal identity.</h3>\n<ul data-path-to-node=\"13\">\n<li><strong>Đáp án:</strong> <strong>A (early adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 8) “<strong>During the early adolescent years</strong> a young person <strong>begins to recognise their uniqueness</strong> and to establish themselves as separate individuals…”</li>\n<li><strong>Giải thích:</strong> Quá trình tự nhận thức sự độc đáo và xây dựng bản sắc riêng bắt đầu ngay từ những năm <strong>đầu</strong> của tuổi vị thành niên.</li>\n</ul>\n<h3 data-path-to-node=\"14\">6. The period when the importance of being accepted by a peer group starts to decrease.</h3>\n<ul data-path-to-node=\"15\">\n<li><strong>Đáp án:</strong> <strong>C (late adolescence)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 10) “Certainly by <strong>late adolescence</strong> or early adulthood the <strong>need for peer approval has diminished</strong>.”</li>\n<li><strong>Giải thích:</strong> Đến giai đoạn <strong>cuối</strong> vị thành niên, nhu cầu được bạn bè thừa nhận đã <strong>giảm bớt</strong> (<em>diminished</em>).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('63f37217-2444-4cdf-bb39-0368b6a1e71e', 'aa8132aa-4cfc-4f48-9552-a816e6b5e417', 'radio', 'Questions 10-13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the 20th century, most of the world’s ambergris came from processing dead whales."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The value of ambergris has increased recently."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Ambergris remains an important ingredient in perfume."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "New uses have recently been found for ambergris."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">10. In the 20th century, most of the world’s ambergris came from processing dead whales — TRUE</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> “In 1963-64 alone… and over 90 per cent of the annual worldwide total was acquired in this way, <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"118\">as a by-product of commercial whaling</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc săn bắt cá voi thương mại (thế kỷ 20) để lấy các bộ phận (carcasses/dead whales) đã cung cấp hơn 90% lượng long diên hương. “Over 90%” tương ứng với “most”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">11. The value of ambergris has increased recently — NOT GIVEN</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc đề cập ở đoạn 1 rằng “At one time, ambergris was worth its weight in gold”. Đoạn cuối nói về việc nó bị thay thế bởi các chất khác.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về giá trị rất cao của nó trong quá khứ, nhưng <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"74\">không có thông tin so sánh</strong> nào về việc giá trị của nó <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"128\">tăng lên trong thời gian gần đây (recently)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">12. Ambergris remains an important ingredient in perfume — FALSE</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> “…so ambergris was <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"41\">supplanted</strong> in the making of perfume by <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"80\">other materials</strong>, some natural and some synthetic in origin.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"15\">“supplanted”</strong> có nghĩa là <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"40\">bị thay thế</strong>. Vì long diên hương đã bị thay thế bởi các nguyên liệu tự nhiên và tổng hợp khác, nó không còn giữ vai trò là thành phần quan trọng (important ingredient) như trước nữa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">13. New uses have recently been found for ambergris — NOT GIVEN</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1 liệt kê các công dụng cổ xưa (thuốc, gia vị, nước hoa).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ tập trung vào các công dụng truyền thống và lịch sử của long diên hương. <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"97\">Không có thông tin</strong> nào đề cập đến việc người ta tìm ra những <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"158\">công dụng mới (new uses)</strong> cho nó trong thời gian gần đây.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('8747a4e6-fc5c-409c-9433-316b4a3cda98', '434607f4-d01e-4b26-9fa0-17e0039b5e45', 'matrix', 'Question 38-40', '', '<p>Write the correct letter, <strong data-path-to-node="9" data-index-in-node="41">A, B, C</strong> or <strong data-path-to-node="9" data-index-in-node="52">D</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Dates", "matrixItems": [{"itemText": "Melbourne: A Portrait received the Book of the Year award.", "correctCategoryLetter": "A"}, {"itemText": "Strizic collaborated with Robin Boyd on Living in Australia.", "correctCategoryLetter": "C"}, {"itemText": "Strizic returned to his early negatives of Melbourne streets for an exhibition.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "1961", "categoryLetter": "A"}, {"categoryText": "1968", "categoryLetter": "B"}, {"categoryText": "1970", "categoryLetter": "C"}, {"categoryText": "1988", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">38. Melbourne: A Portrait received the Book of the Year award. — {A. 1961}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“In <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">1961</strong> it [Melbourne: A Portrait] was awarded <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"68\">Book of the Year</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ mốc thời gian cuốn sách về Melbourne nhận giải thưởng là năm 1961.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">39. Strizic collaborated with Robin Boyd on Living in Australia. — {C. 1970}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“That <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">same year [1970]</strong>, Strizic worked with the influential architect <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"90\">Robin Boyd</strong> on <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"104\">Living in Australia</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “That same year” ám chỉ mốc thời gian 1970 đã được nhắc đến ở cuối đoạn 6 (khi nói về sự hợp tác với Stanislav Ostoja-Kotkowski). Đây là năm ông làm việc với Robin Boyd cho cuốn sách Living in Australia.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">40. Strizic returned to his early negatives of Melbourne streets for an exhibition. — {D. 1988}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“In <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"24\">1988</strong> he <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"32\">returned to his earliest negatives of Melbourne</strong>, staging an <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"92\">exhibition</strong> that highlighted his long-standing interest…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mốc thời gian 1988 đánh dấu sự kiện Strizic sử dụng lại những bản phim âm bản thời kỳ đầu để tổ chức một buổi triển lãm về đường phố Melbourne.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('2c56bcc1-8ded-47a0-9054-f97955532734', '136a6a3b-67a3-465a-a956-984c7b8ec061', 'fillup', 'Questions 22-26', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
<p>There is little information on the origin of the tomato despite the existence of  {archaeological} data on the growing of other New World crops.</p>
<p>Although it is uncertain, the tomato is thought to have first grown in the {Andes}  .</p>
<p>In regard to genetic similarities, the {currant}  tomato is the nearest to the earliest type of tomato.</p>
<p>A genetic {mutation}  which is evident in pomodoro produced larger tomatoes.</p>
<p>{infections}  are а problem for heirloom tomatoes because they frequently lead to damage and deterioration.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>22. There is little information on the origin of the tomato despite the existence of <strong>archaeological</strong> data on the growing of other New World crops.</p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong>Đáp án:</strong> <strong>archaeological</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “But whereas scientists have uncovered a wealth of <strong>archaeological</strong> evidence on early farming practices in the New World, the record is blank when it comes to the tomato.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong>Giải thích:</strong> Dữ liệu khảo cổ học (<strong>archaeological</strong>) phong phú về các cây trồng khác ở Tân Thế giới, nhưng lại thiếu thông tin về cà chua.</p>\n</li>\n</ul>\n<p>23. Although it is uncertain, the tomato is thought to have first grown in the <strong>Andes</strong>.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>Andes</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “The modern tomato seems to have its origins in the <strong>Andes</strong> in South America, and may have been domesticated in Vera Cruz, Mexico.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Cà chua được cho là có nguồn gốc từ vùng Andes.</p>\n</li>\n</ul>\n<p>24. In regard to genetic similarities, the <strong>currant</strong> tomato is the nearest to the earliest type of tomato.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>currant</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “The closest relative is the <strong>currant</strong> tomato which, based on genetic comparisons, split from today’s tomato some 1.4 million years ago.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Cà chua currant là họ hàng gần nhất (nearest) với loại cà chua sớm nhất.</p>\n</li>\n</ul>\n<p>25. A genetic <strong>mutation</strong> which is evident in pomodoro produced larger tomatoes.</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>mutation</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “…Tanksley concludes… our ancestors ultimately exploited just 30 <strong>mutations</strong> out of the tomato’s 35,000 genes… The first written record of tomatoes… confirms that this <strong>mutation</strong>, which enlarges tomatoes… existed back in the same yellow tomatoes that gave Italians the word <em>pomodoro</em>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Sự thay đổi di truyền làm cà chua lớn hơn được gọi là <strong>mutation</strong> (đột biến).</p>\n</li>\n</ul>\n<p>26. <strong>Infections</strong> are a problem for heirloom tomatoes because they frequently lead to damage and deterioration.</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>Infections</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “They often suffer from <strong>infections</strong> that cause the fruit to crack, split and otherwise rot quickly.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Cà chua heirloom dễ bị <strong>infections</strong> (nhiễm trùng) dẫn đến hư hỏng và thối rữa</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('d665eb7b-d8e8-4a7a-8d19-1ad34dce848a', 'aac6c9e0-0787-432b-9cd7-9e089e93cb78', 'radio', 'Question 40', '', '<p data-path-to-node="2">Choose the correct letter,<strong data-path-to-node="2" data-index-in-node="0"> A, B, C </strong>or<strong data-path-to-node="2" data-index-in-node="0"> D.</strong></p>
<p data-path-to-node="3">Write the correct letter in box 40 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A A look at what ''Henry'' has achieved in Leeds"}, {"option_text": "B ''Henry''s the best,'' according to Leeds children"}, {"option_text": "C Leeds parents discuss how ''Henry'' has helped them"}, {"option_text": "D It''s all about saying ''no'', according to ''Henry''"}], "question": "Which title is the most suitable for the text?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">40. Which title is the most suitable for the text? — {A} A look at what ‘Henry’ has achieved in Leeds</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> &gt; “Leeds has become the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"35\">first city in the UK to report a drop in childhood obesity</strong> after introducing a programme called <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"131\">‘Henry’</strong>… It could involve a programme called ‘Henry’ that the city introduced as the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"218\">core of its obesity strategy</strong> in 2009.” (Đoạn 1 &amp; 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xuyên suốt bài đọc là sự kết hợp giữa các số liệu thống kê về sự sụt giảm tỷ lệ béo phì (thành tựu) và các phân tích về cách thức vận hành của chương trình “Henry” tại Leeds. Các ý kiến từ chuyên gia (Susan Jebb) và phụ huynh (Lisa) đều tập trung làm sáng tỏ kết quả mà chương trình này đã đạt được.</p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('0c2ab452-2e5e-4cbd-8619-5fa8112e9a73', '29e5cc96-a84b-4aa2-b895-6e20a65caf50', 'fillup', 'Questions 1–10', '<p data-start="128" data-end="179">Write <strong data-start="134" data-end="162">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9971%;" border="1"><colgroup> <col style="width: 99.8607%;"></colgroup>
