<p> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">1. piston — {the movement of the piston was linked to a gear system}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"...invent a new steam engine driven by both the forward and backward strokes of the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"105\">piston</strong>, while the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"123\">gear mechanism</strong> it was connected to produced rotary motion.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói động cơ của Watt và Boulton được điều khiển bởi chuyển động của pít-tông (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"98\">piston</strong>) và được kết nối với hệ thống bánh răng (gear mechanism).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">2. coal — {A greater supply of coal was required to power steam engines}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"The demand for <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"36\">coal</strong>... grew rapidly... as it was needed to run not only the factories... but also <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"119\">steam-powered transportation</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhu cầu (demand) tăng nhanh đồng nghĩa với việc cần một nguồn cung lớn hơn (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"88\">greater supply</strong>) than đá (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"113\">coal</strong>) để chạy các động cơ hơi nước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">3. workshops — {spinners and weavers worked at home and in workshops}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"...with the work performed in small <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"57\">workshops</strong> or even <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"75\">homes</strong> by individual spinners, weavers...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước cách mạng công nghiệp, những người thợ làm việc tại nhà (homes) hoặc trong các xưởng nhỏ (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"108\">workshops</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">4. labour (hoặc labor) — {Not as much labour was needed to produce cloth}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">\"With these machines, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"42\">relatively little labour was required</strong> to produce cloth...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Relatively little labour was required\" tương ứng với \"Not as much labour was needed\" (không cần nhiều nhân công/sức lao động như trước).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">5. quality — {Smelting... resulted in material that was better quality}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">\"This method was cheaper and produced metals that were of a <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"80\">higher quality</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phương pháp luyện quặng sắt với than cốc tạo ra kim loại có chất lượng cao hơn (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"92\">higher quality</strong> / <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"109\">better quality</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">6. railway — {Demand for iron increased with the growth of the railway}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">\"...enabling Britain''s iron and steel production to expand in response to... the expansion of the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"118\">railways</strong> from the 1830s.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Expansion\" đồng nghĩa với \"growth\". Nhu cầu sắt thép tăng lên cùng với sự phát triển của ngành đường sắt (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"119\">railway</strong> hoặc <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"132\">railways</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">7. sanitation — {The new cities... lacked sufficient sanitation}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"20\">\"...overcrowded cities suffered from pollution and <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"71\">inadequate sanitation</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Inadequate\" (không đầy đủ/thiếu thốn) tương ứng với \"lacked sufficient\". Các thành phố mới đối mặt với tình trạng thiếu vệ sinh (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"142\">sanitation</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('0fade549-5b5c-415a-97a2-8d67a1a2b963', '441e8c6f-92df-40ec-8c3e-13f4cd105d4c', 'fillup', 'Questions 1-10', '<p data-start="120" data-end="171"><strong data-start="120" data-end="171">Write ONE WORD AND/OR A NUMBER for each answer.</strong></p>
<p style="text-align: center;" data-start="120" data-end="171"><strong>Furniture Rental Companies</strong></p>
