<table class="MsoNormalTable" style="width: 100%; border-collapse: collapse; border: 1px solid rgb(0, 0, 0); height: 295.2px; border-spacing: 1px;" border="1" width="100%" cellspacing="0" cellpadding="0">
<thead>
