INSERT INTO public.questions VALUES ('b85fce93-670f-43c3-bcca-7aa224a04fd1', 'c763d63f-1ae5-4600-b623-fdeb3233703a', 'checkbox', 'Questions 11 and 12', '', '<p data-start="154" data-end="182"><strong data-start="154" data-end="182">Choose TWO letters, A–E.</strong></p>
<p data-start="184" data-end="266">Which <strong>TWO</strong> problems with some training programmes for new runners does Liz mention?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A There is a risk of serious injury."}, {"correct": false, "option_text": "B They are unsuitable for certain age groups."}, {"correct": true, "option_text": "C They are unsuitable for people with health issues."}, {"correct": false, "option_text": "D It is difficult to stay motivated."}, {"correct": true, "option_text": "E There is a lack of individual support."}]', 'null', 'null', '[{"content": "<p data-start=\"170\" data-end=\"334\">My name’s Liz Fuller and I’m a running coach with Compton Park Runners Club. Welcome to my podcast. If you’re thinking about taking up running – I’m here to help.</p>\n<p data-start=\"336\" data-end=\"1001\">There are many training programmes available online which aim to help people build up to running 5 kilometres. Some of them are great and thousands of people of all ages are taking part in 5-kilometre races across the country as a result. People like them because they’re easy to follow and don’t push them too hard. However, <span style=\"background-color: #f1c40f;\"><strong>(11) they don’t work for everyone – especially if you suffer from something like a heart condition or asthma</strong></span>, because they’re aimed at people with average fitness and running ability. Another thing is that everyone is different – and <span style=\"background-color: #f1c40f;\"><strong>(12) if you have any specific questions related to your needs, there’s no one to provide any answer</strong></span></p>\n<p data-start=\"1003\" data-end=\"1784\">I have a couple of simple tips I always give to new runners. Expect you’ve been told to run very slowly until your fitness increases – well, I find that can prevent progress. You should run at a speed that feels comfortable, but push yourself and try to run a bit faster each time. <strong><span style=\"background-color: #f1c40f;\">(13) Listening to music can be very helpful – it takes your mind off things and helps your body get into a rhythm</span></strong>. I’d say that is better than running with a friend – especially as most people are competitive and that’s not what you want when you’re just starting. I don’t think the time of day is especially important – some people are better in the evening, while others are morning people – but you need to be consistent, <span style=\"background-color: #f1c40f;\"><strong>(14) so aim to train regularly – twice a week is enough to begin with</strong></span></p>\n<p data-start=\"1786\" data-end=\"2241\">New members often say to me that they’ve been put off running either because they lack confidence, or they don’t have time, or they dislike running. Ceri, for example, joined the club two years ago at the age of 40. She’d always enjoyed running at school but <span style=\"background-color: #f1c40f;\"><strong>(15) wasn’t sure if she’d be able to do it. She was worried about being left behind and being the slowest runner</strong></span>. But she says she was made to feel so welcome she soon forgot all about that</p>\n<p data-start=\"2243\" data-end=\"2460\"><strong><span style=\"background-color: #f1c40f;\">(16) James had always hated the idea of running </span></strong>but a friend encouraged him to come along for a taster session and he hasn’t looked back. He never misses a training session despite having a really demanding job.</p>\n<p data-start=\"2462\" data-end=\"2784\">Leo was worried about having to commit himself to training sessions every week and <span style=\"background-color: #f1c40f;\"><strong>(17) wasn’t sure he’d be able to fit training into his busy schedule</strong></span>. But after experiencing a lot of stress at work he came along to us and gave it a go. Now he says he feels much more relaxed and he looks forward to his weekly run.</p>\n<p data-start=\"2786\" data-end=\"3173\">Mark is quite typical of our new members. He’s never considered himself to be a sporty person and it was only when he retired that he decided to take up the challenge of trying to run 5 kilometres. <span style=\"background-color: #f1c40f;\"><strong>(18) It took him months to find the courage to contact us </strong></span>but he felt reassured immediately as there were other people his age who were only just taking up running for the first time .</p>\n<p data-start=\"3175\" data-end=\"3526\">My own journey hasn’t been easy. I did my first marathon when I was 37, after having had two kids. My husband had been running marathons for years, but I never dreamed I’d be doing one with him. I managed to complete it in four hours, but <strong><span style=\"background-color: #f1c40f;\">(19) I felt like giving up halfway through – it was only the support of the spectators that kept me going.</span></strong></p>\n<p data-start=\"3528\" data-end=\"4074\">I do think signing up for a race of whatever length is motivating – whether it’s 5K or 25K – because it’s good to have something to work towards and it gives you a sense of achievement. I did my first 10K after only six months, which was certainly very challenging and not something I’d necessarily recommend. But <span style=\"background-color: #f1c40f;\"><strong>(20) after you’ve been training for a few weeks, it’s worth putting your name down for a 5K </strong></span>– some people find they only need a few practice runs before taking part in a race, but I’d give yourself a couple of months at least .</p>\n<p data-start=\"4076\" data-end=\"4105\">Well, I hope that’s given …</p>"}]', 0);
INSERT INTO public.questions VALUES ('9c923a4c-bec7-4c8a-9e4f-3949de7ffa84', 'c763d63f-1ae5-4600-b623-fdeb3233703a', 'checkbox', 'Questions 13 and 14', '', '<p data-start="526" data-end="554"><strong data-start="526" data-end="554">Choose TWO letters, A–E.</strong></p>
<p data-start="556" data-end="606">Which TWO tips does Liz recommend for new runners?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A doing two runs a week"}, {"correct": false, "option_text": "B running in the evening"}, {"correct": false, "option_text": "C going on runs with a friend"}, {"correct": true, "option_text": "D listening to music during runs"}, {"correct": false, "option_text": "E running very slowly"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('bcc3da35-fe2f-432a-be28-cf78e65cba15', 'c763d63f-1ae5-4600-b623-fdeb3233703a', 'matrix', 'Questions 15–18', '', '<p>What reason prevented each of the following members of the Compton Park Runners Club from joining until recently?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of option", "matrixItems": [{"itemText": "Ceri", "correctCategoryLetter": "A"}, {"itemText": "James", "correctCategoryLetter": "B"}, {"itemText": "Leo", "correctCategoryLetter": "C"}, {"itemText": "Mark", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "a lack of confidence", "categoryLetter": "A"}, {"categoryText": "a dislike of running", "categoryLetter": "B"}, {"categoryText": "a lack of time", "categoryLetter": "C"}]}', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('9008effd-7ed3-43e9-b4a7-45f7e5706556', 'c763d63f-1ae5-4600-b623-fdeb3233703a', 'radio', 'Questions 19 and 20', '', '<p><strong data-start="1203" data-end="1244">Choose the correct letter, A, B or C.</strong></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A It had always been her ambition."}, {"option_text": "B Her husband persuaded her to do it."}, {"option_text": "C She nearly gave up before the end."}], "question": "What does Liz say about running her first marathon?"}, {"correct": 1, "options": [{"option_text": "A every six months."}, {"option_text": "B within a few weeks of taking up running."}, {"option_text": "C after completing several practice runs."}], "question": "Liz says new runners should sign up for a race"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 3);
INSERT INTO public.questions VALUES ('aa2dc2ca-4332-4292-b616-1919e2ec1b18', 'c2afea58-2526-47da-8674-c73f378d1946', 'matching', 'Questions 1-8', '', '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Write the correct number, <strong data-path-to-node="4" data-index-in-node="149">i-x</strong>, in boxes 1-8 on your answer sheet.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i  Not enough tea to meet demand"}, {"optionText": "ii  Religious objections"}, {"optionText": "iii In and sometimes out of fashion"}, {"optionText": "iv A connection between tea and religion"}, {"optionText": "v A luxury item"}, {"optionText": "vi News of tea reaches another continent"}, {"optionText": "vii Is tea a good or a bad thing?"}, {"optionText": "viii A chance discover"}, {"optionText": "ix Tea-making as a ritual"}, {"optionText": "x Difficulties in importing tea"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1: {viii. A chance discovery}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Dried leaves from a nearby bush <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"44\">fell into the boiling water</strong>… the Emperor was intrigued by the new liquid, drank some, and found it very refreshing.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc lá trà rơi vào nồi nước sôi là một sự kiện ngẫu nhiên (by chance). Hoàng đế không chủ ý pha trà từ đầu, nên đây được coi là một cuộc <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"150\">phát kiến tình cờ</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2: {iv. A connection between tea and religion}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…reflecting <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">Zen Buddhist philosophy</strong>… brought to Japan by a returning <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"85\">Buddhist priest</strong>… enhancing <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"114\">meditation</strong>… linked with Zen Buddhism.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này lặp đi lặp lại các thuật ngữ liên quan đến tôn giáo như: Phật giáo Thiền tông (Zen Buddhism), thầy tu (priest), thiền định (meditation).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3: {ix. Tea-making as a ritual}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tea was elevated to an <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"35\">art form in the Japanese tea ceremony</strong>… most perfect, most polite, most graceful… manner possible.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ceremony” (nghi lễ) và cách thức pha trà tỉ mỉ, lịch sự chính là biểu hiện của một <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">nghi thức (ritual)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4: {vi. News of tea reaches another continent}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…information concerning the then-unknown beverage began to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"73\">filter back to Europe</strong>… The first European to personally encounter tea…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trà vốn ở châu Á, đoạn này kể về việc thông tin về trà bắt đầu truyền sang <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"87\">châu Âu</strong> (một lục địa khác – <em data-path-to-node=\"11,1,0\" data-index-in-node=\"115\">another continent</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5: {v. A luxury item}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…due in part to tea being <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"40\">very expensive (over $100 per pound)</strong>, which immediately made it the domain of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"122\">wealthy</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì giá trà rất đắt đỏ và chỉ dành cho người giàu nên nó được coi là một <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"84\">mặt hàng xa xỉ (luxury item)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6: {vii. Is tea a good or a bad thing?}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…doctors and university authorities in Holland <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"61\">argued as to its benefits or drawbacks</strong>… the controversy lasted…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tranh luận về lợi ích (benefits) hay tác hại (drawbacks) chính là đang xem xét trà là <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"103\">thứ tốt hay xấu</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7: {iii. In – and sometimes out – of fashion}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tea remained popular in France for only about fifty years, <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"71\">being replaced by a preference for wine, chocolate and exotic coffees</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trà từng rất được ưa chuộng (in fashion) nhưng sau đó lại bị thay thế bởi các thức uống khác (out of fashion) tại Pháp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8: {x. Difficulties in importing tea}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Still, the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"23\">journey was not easy</strong>. The average caravan consisted of 200 to 300 camels and the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"104\">18,000-kilometre trip took over 16 months</strong> to complete.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này mô tả sự khắc nghiệt của quãng đường vận chuyển trà từ Trung Quốc sang Nga, tức là những <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"110\">khó khăn trong việc nhập khẩu</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('3efdb0a6-9f11-4820-a5eb-d29d8850e804', '3da52ade-c29b-4d87-bb2b-42e6d4e27a85', 'radio', 'Questions 21–25', '', '<p data-start="154" data-end="195"><strong data-start="154" data-end="195">Choose the correct letter, A, B or C.</strong></p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A common sense."}, {"option_text": "B hard to follow."}, {"option_text": "C over-protective."}], "question": "Kieran thinks the packing advice given by Jane’s grandfather is"}, {"correct": 2, "options": [{"option_text": "A They are not worth keeping."}, {"option_text": "B They should go to a collector."}, {"option_text": "C They have sentimental value for her."}], "question": "How does Jane feel about the books her grandfather has given her?"}, {"correct": 0, "options": [{"option_text": "A put out on display."}, {"option_text": "B given as gifts to visitors."}, {"option_text": "C more attractively designed."}], "question": " Jane and Kieran agree that hardback books should be"}, {"correct": 1, "options": [{"option_text": "A describes the mistakes other people make doing it."}, {"option_text": "B reflects on a significant childhood experience."}, {"option_text": "C explains why some books are easier to remove than others."}], "question": "While talking about taking a book from a shelf, Jane"}, {"correct": 2, "options": [{"option_text": "A Their parents liked buying them as presents."}, {"option_text": "B They would like to buy more of them."}, {"option_text": "C Not everyone can afford them."}], "question": "What do Jane and Kieran suggest about new books?"}]', 'null', 'null', 'null', '[{"content": "<p data-start=\"170\" data-end=\"250\"><strong data-start=\"170\" data-end=\"181\">KIERAN:</strong> So Jane – you’ll be off to Denmark soon to do your work placement.</p>\n<p data-start=\"252\" data-end=\"366\"><strong data-start=\"252\" data-end=\"261\">JANE:</strong> Yes, I’m really looking forward to it and I’ve just started packing up all my books to put in storage.</p>\n<p data-start=\"368\" data-end=\"417\"><strong data-start=\"368\" data-end=\"379\">KIERAN:</strong> Well, I hope they don’t get spoilt.</p>\n<p data-start=\"419\" data-end=\"508\"><strong data-start=\"419\" data-end=\"428\">JANE:</strong> It’s OK – my grandfather works in a bookshop and he told me how to pack them.</p>\n<p data-start=\"510\" data-end=\"543\"><strong data-start=\"510\" data-end=\"521\">KIERAN:</strong> Oh, that’s helpful.</p>\n<p data-start=\"545\" data-end=\"653\"><strong data-start=\"545\" data-end=\"554\">JANE:</strong> He says <span style=\"background-color: #f1c40f;\"><strong>(21)</strong> <strong>you have to support the spine otherwise the paper can come away from the cover </strong></span>.</p>\n<p data-start=\"655\" data-end=\"691\"><strong data-start=\"655\" data-end=\"666\">KIERAN:</strong> <span style=\"background-color: #f1c40f;\"><strong>Yeah – that’s obvious.</strong></span></p>\n<p data-start=\"693\" data-end=\"903\"><span style=\"background-color: #f1c40f;\"><strong>JANE: He also told me to pack them flat in the box not on their side – again because they can bend and if you leave them like that for, say, a year, it’s quite hard to get them back to their normal shape.</strong></span></p>\n<p data-start=\"910\" data-end=\"1031\"><strong data-start=\"910\" data-end=\"921\">KIERAN:</strong> <span style=\"background-color: #f1c40f;\"><strong>Well, it’s pretty clear that ruins them,</strong></span> but a lot of people just can’t be bothered to protect their books.</p>\n<p data-start=\"1033\" data-end=\"1125\"><strong data-start=\"1033\" data-end=\"1042\">JANE:</strong> He always says it’s such a shame that publishers don’t use better-quality paper.</p>\n<p data-start=\"1127\" data-end=\"1202\"><strong data-start=\"1127\" data-end=\"1138\">KIERAN:</strong> It’s the acid in the paper that causes the problem, isn’t it?</p>\n<p data-start=\"1204\" data-end=\"1330\"><strong data-start=\"1204\" data-end=\"1213\">JANE:</strong> Yeah – that’s why old books go yellow. You know some of the books my grandfather’s given me are like that already.</p>\n<p data-start=\"1332\" data-end=\"1349\"><strong data-start=\"1332\" data-end=\"1343\">KIERAN:</strong> Oh…</p>\n<p data-start=\"1351\" data-end=\"1489\"><strong data-start=\"1351\" data-end=\"1360\">JANE:</strong> <span style=\"background-color: #f1c40f;\"><strong>(22) </strong><strong>I should dump them really if they’re going to deteriorate further, but I’d feel bad. They’ll always remind me of him</strong></span>.</p>\n<p data-start=\"1491\" data-end=\"1540\"><strong data-start=\"1491\" data-end=\"1502\">KIERAN:</strong> Well, if they’re important to you …</p>\n<p data-start=\"1542\" data-end=\"1596\"><strong data-start=\"1542\" data-end=\"1551\">JANE:</strong> Yeah – I’d regret just throwing them away.</p>\n<p data-start=\"1603\" data-end=\"1794\"><strong data-start=\"1603\" data-end=\"1614\">KIERAN:</strong> You know, maybe it’s because I was taught to treasure books … but I hate seeing students force open the pages – of paperbacks. They press so hard they end up breaking the spine.</p>\n<p data-start=\"1796\" data-end=\"1935\"><strong data-start=\"1796\" data-end=\"1805\">JANE:</strong> I know, but unfortunately, paperbacks aren’t designed to last a long time and people know that. Hardbacks aren’t quite as weak.</p>\n<p data-start=\"1937\" data-end=\"2052\"><strong data-start=\"1937\" data-end=\"1948\">KIERAN:</strong> Yeah, they’re different, I suppose. But I still don’t think people value hardbacks like they used to.</p>\n<p data-start=\"2054\" data-end=\"2339\"><strong data-start=\"2054\" data-end=\"2063\">JANE:</strong> Well, they aren’t decorative, are they, like other objects. Plus, nowadays, people don’t keep them out on shelves as much as they used to. <span style=\"background-color: #f1c40f;\"><strong>(23)</strong><strong>That’s such a pity. When I visit someone – if they have, say, a colourful book on a table, it’s the first thing I’m drawn to</strong></span></p>\n<p data-start=\"2341\" data-end=\"2446\"><strong data-start=\"2341\" data-end=\"2352\">KIERAN:</strong> <span style=\"background-color: #f1c40f;\"><strong>I agree – and book covers can be a work of art in themselves. Some are really eye-catching.</strong></span></p>\n<p data-start=\"2453\" data-end=\"2593\"><strong data-start=\"2453\" data-end=\"2462\">JANE:</strong> I’ve always been taught to handle books carefully. If you watch someone take a book off a shelf, well, they usually do it wrong.</p>\n<p data-start=\"2595\" data-end=\"2793\"><strong data-start=\"2595\" data-end=\"2606\">KIERAN:</strong> Ah, my grandfather says you should put your hand right over the top of the book … or if you can’t do that, pull the other books on the shelf aside so that you can hold the whole cover.</p>\n<p data-start=\"2795\" data-end=\"2835\"><strong data-start=\"2795\" data-end=\"2804\">JANE:</strong> When did you learn all this?</p>\n<p data-start=\"2837\" data-end=\"2964\"><strong data-start=\"2837\" data-end=\"2848\">KIERAN:</strong> <span style=\"background-color: #f1c40f;\"><strong>(24) I watched me pull a heavy book off the shelf when I was small, and it fell on the floor and broke apart .</strong></span></p>\n<p data-start=\"2966\" data-end=\"2986\"><strong data-start=\"2966\" data-end=\"2975\">JANE:</strong> Oh dear!</p>\n<p data-start=\"2993\" data-end=\"3031\"><strong data-start=\"2993\" data-end=\"3004\">KIERAN:</strong> I can still remember it!</p>\n<p data-start=\"3033\" data-end=\"3073\"><strong data-start=\"3033\" data-end=\"3042\">JANE:</strong> You know what I really like?</p>\n<p data-start=\"3075\" data-end=\"3094\"><strong data-start=\"3075\" data-end=\"3086\">KIERAN:</strong> What?</p>\n<p data-start=\"3096\" data-end=\"3131\"><strong data-start=\"3096\" data-end=\"3105\">JANE:</strong> The smell of new books.</p>\n<p data-start=\"3133\" data-end=\"3154\"><strong data-start=\"3133\" data-end=\"3144\">KIERAN:</strong> Me too.</p>\n<p data-start=\"3156\" data-end=\"3292\"><strong data-start=\"3156\" data-end=\"3165\">JANE:</strong> My parents used to laugh at me when I was a kid because I loved putting books up to my nose. Almost as much as reading them!</p>\n<p data-start=\"3294\" data-end=\"3349\"><strong data-start=\"3294\" data-end=\"3305\">KIERAN: <span style=\"background-color: #f1c40f;\">(25) </span></strong><strong><span style=\"background-color: #f1c40f;\">N</span>ew books aren’t cheap, though, are they?</strong></p>\n<p data-start=\"3351\" data-end=\"3408\"><strong data-start=\"3351\" data-end=\"3360\">JANE:</strong> <span style=\"background-color: #f1c40f;\"><strong>I guess we’re lucky we can buy them .</strong></span></p>\n<p data-start=\"3410\" data-end=\"3519\"><strong data-start=\"3410\" data-end=\"3421\">KIERAN:</strong> My grandfather stocks second-hand books as well as new ones and they don’t smell quite as good.</p>\n<hr data-start=\"3521\" data-end=\"3524\">\n<p data-start=\"3526\" data-end=\"3606\"><strong data-start=\"3526\" data-end=\"3537\">KIERAN:</strong> I’d love to have a bookshop like your grandfather. What’s it like?</p>\n<p data-start=\"3608\" data-end=\"3717\"><strong data-start=\"3608\" data-end=\"3617\">JANE:</strong> Well, it’s quite big – it’s got two floors and an attic, and he stocks all kinds of books really.</p>\n<p data-start=\"3719\" data-end=\"3802\"><strong data-start=\"3719\" data-end=\"3730\">KIERAN:</strong> I guess he treasures things like first editions and other rare books.</p>\n<p data-start=\"3804\" data-end=\"3903\"><strong data-start=\"3804\" data-end=\"3813\">JANE:</strong> Yeah – you might think he’d keep those in the attic or somewhere … so they’d be hidden?</p>\n<p data-start=\"3905\" data-end=\"3918\"><strong data-start=\"3905\" data-end=\"3916\">KIERAN:</strong></p>\n<p data-start=\"3920\" data-end=\"4071\"><strong data-start=\"3920\" data-end=\"3929\">JANE:</strong> Yeah. But he likes people to know that he has them. <strong><span style=\"background-color: #f1c40f;\">(26) So, he puts them out in the shop but makes sure you need a ladder to get them</span></strong></p>\n<p data-start=\"4073\" data-end=\"4124\"><strong data-start=\"4073\" data-end=\"4084\">KIERAN:</strong> Right. That would prevent any thefts!</p>\n<p data-start=\"4131\" data-end=\"4178\"><strong data-start=\"4131\" data-end=\"4142\">KIERAN:</strong> Does he stock books for children?</p>\n<p data-start=\"4180\" data-end=\"4352\"><strong data-start=\"4180\" data-end=\"4189\">JANE:</strong> He does. He particularly likes to encourage kids to read; he always says that he used to sit under the stairs as a child with a pile of books and read them all.</p>\n<p data-start=\"4354\" data-end=\"4402\"><strong data-start=\"4354\" data-end=\"4365\">KIERAN:</strong> Is that where he keeps them, then?</p>\n<p data-start=\"4404\" data-end=\"4591\"><strong data-start=\"4404\" data-end=\"4413\">JANE:</strong> Not exactly – <span style=\"background-color: #f1c40f;\"><strong>(27) he’s got a dedicated area on the ground floor with cushions so that parents can enter with their toddlers, go there and spend some time reading to them</strong></span>.</p>\n<p data-start=\"4598\" data-end=\"4720\"><strong data-start=\"4598\" data-end=\"4609\">KIERAN:</strong> Oh cool. And then there’s a place for pushchairs by the front door. And a café if anyone needs refreshments.</p>\n<p data-start=\"4722\" data-end=\"4754\"><strong data-start=\"4722\" data-end=\"4731\">JANE:</strong> That’s good to know.</p>\n<p data-start=\"4756\" data-end=\"4845\"><strong data-start=\"4756\" data-end=\"4767\">KIERAN:</strong> As I said, it’s a big shop and there’s a storage area out the back as well.</p>\n<p data-start=\"4847\" data-end=\"4917\"><strong data-start=\"4847\" data-end=\"4856\">JANE:</strong> Oh, what does he keep there? Books he wants to throw away?</p>\n<p data-start=\"4919\" data-end=\"5050\"><strong data-start=\"4919\" data-end=\"4930\">KIERAN:</strong> He hardly ever throws anything away –<strong><span style=\"background-color: #f1c40f;\"> (28) he just leaves unwanted books by the front door for customers to take.</span></strong></p>\n<p data-start=\"5057\" data-end=\"5094\"><strong data-start=\"5057\" data-end=\"5068\">KIERAN:</strong> Well, that’s very nice.</p>\n<p data-start=\"5096\" data-end=\"5200\"><strong data-start=\"5096\" data-end=\"5105\">JANE:</strong> Yeah – and <span style=\"background-color: #f1c40f;\"><strong>(29) books people or institutions have requested, they all go at the far end.</strong></span></p>\n<p data-start=\"5202\" data-end=\"5219\"><strong data-start=\"5202\" data-end=\"5213\">KIERAN:</strong> Oh.</p>\n<p data-start=\"5226\" data-end=\"5329\"><strong data-start=\"5226\" data-end=\"5237\">KIERAN:</strong> He thinks it’s best to keep these out of the main shopping area as they’re boxed and new.</p>\n<p data-start=\"5331\" data-end=\"5381\"><strong data-start=\"5331\" data-end=\"5340\">JANE:</strong> Did you get your coursebooks from him?</p>\n<p data-start=\"5383\" data-end=\"5679\"><strong data-start=\"5383\" data-end=\"5394\">KIERAN:</strong> Naturally. He stocks books for a lot of the colleges. He used to keep these books on the first floor, but now there’s a new university in my hometown, <span style=\"background-color: #f1c40f;\"><strong>(30) he’s moved them downstairs to attract the students. They’re actually part of the coffee shop on low shelves all around it</strong></span>.</p>"}]', 0);
INSERT INTO public.questions VALUES ('84c488f7-1285-40ff-afbb-152182000c08', 'c2afea58-2526-47da-8674-c73f378d1946', 'matrix', 'Questions 9–13', '', '<p>Look at the following statements (Question 9–13) and the list of countries below.</p>
<p>Match each statement with the correct country, <strong>A</strong>–<strong>G</strong>.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of countries", "matrixItems": [{"itemText": "Claims that tea might be harmful failed to affect its popularity.", "correctCategoryLetter": "D"}, {"itemText": "Tea lost favour to other drinks.", "correctCategoryLetter": "E"}, {"itemText": "Special buildings were constructed in which to drink tea.", "correctCategoryLetter": "B"}, {"itemText": "Animals were involved in importing tea.", "correctCategoryLetter": "G"}, {"itemText": "A ruler’s specialist knowledge led to an interest in tea.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "China", "categoryLetter": "A"}, {"categoryText": "Japan", "categoryLetter": "B"}, {"categoryText": "Portugal", "categoryLetter": "C"}, {"categoryText": "Holland", "categoryLetter": "D"}, {"categoryText": "France", "categoryLetter": "E"}, {"categoryText": "England", "categoryLetter": "F"}, {"categoryText": "Russia", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">9. Claims that tea might be harmful failed to affect its popularity. — {D: Holland}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">doctors and university authorities in </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"53\">Holland</strong><span class=\"\"> argued as to its benefits or </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"90\">drawbacks</strong><span class=\"\">.</span><span class=\"\"> The </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"105\">public largely ignored the scholarly debate</strong><span class=\"\"> and continued to enjoy their new beverage…</span><span class=\"\">” (Đoạn 6)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Harmful” tương ứng với “drawbacks” (tác hại).</span><span class=\"\"> Việc công chúng phớt lờ các cuộc tranh luận và tiếp tục thưởng thức trà cho thấy những lời cảnh báo không làm ảnh hưởng đến sự phổ biến của nó tại Hà Lan.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">10. Tea lost favour to other drinks. — {E: France}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Tea remained popular in </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"36\">France</strong><span class=\"\"> for only about fifty years,</span> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"71\">being replaced by a preference for wine, chocolate and exotic coffees</strong><span class=\"\">.</span><span class=\"\">” (Đoạn 7)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Lost favour” (không còn được ưa chuộng) tương ứng với việc bị thay thế bởi rượu vang,</span><span class=\"\"> sô-cô-la và cà phê tại Pháp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">11. Special buildings were constructed in which to drink tea. — {B: Japan}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">prompted the creation of a </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">particular form of architecture for tea houses</strong><span class=\"\"> [in </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"93\">Japan</strong><span class=\"\">],</span><span class=\"\"> duplicating the simplicity of a forest cottage.</span><span class=\"\">” (Đoạn 3)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Special buildings” chính là các “tea houses” (trà thất) với lối kiến trúc riêng biệt được xây dựng tại Nhật Bản.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">12. Animals were involved in importing tea. — {G: Russia}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “The average </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"24\">caravan</strong><span class=\"\"> consisted of </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"45\">200 to 300 camels</strong><span class=\"\"> and the 18,</span><span class=\"\">000-kilometre trip [to </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"97\">Russia</strong><span class=\"\">] took over 16 months to complete.</span><span class=\"\">” (Đoạn 8)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc sử dụng lạc đà (camels) để vận chuyển trà sang Nga chính là sự tham gia của động vật trong quá trình nhập khẩu.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">13. A ruler’s specialist knowledge led to an interest in tea. — {A: China}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">the </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"19\">Emperor Shen Nung [of China]</strong><span class=\"\"> was a skilled ruler,</span> <strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"69\">creative scientist</strong><span class=\"\">…</span><span class=\"\"> As a scientist,</span><span class=\"\"> the Emperor was </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"123\">intrigued by the new liquid</strong><span class=\"\">,</span><span class=\"\"> drank some,</span><span class=\"\"> and found it very refreshing.</span><span class=\"\">” (Đoạn 1)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong class=\"\" data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Ruler” là Hoàng đế Thần Nông,</span><span class=\"\"> “specialist knowledge” tương ứng với vai trò nhà khoa học (scientist) của ông.</span><span class=\"\"> Chính sự tò mò và kiến thức của ông đã dẫn đến việc khám phá ra trà.</span></p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('7b51e99f-b561-4edc-9c64-391490c3c89f', '3da52ade-c29b-4d87-bb2b-42e6d4e27a85', 'matching', 'Questions 26–30', '', '<p data-start="1215" data-end="1311">Where does Jane’s grandfather keep each of the following types of books in his shop?</p>
<p data-start="1215" data-end="1311">Choose <strong>FIVE </strong>answers from the box and write the correct letter, <strong>A</strong>–<strong>G</strong>, next to Questions 26–30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\"><strong data-start=\"1516\" data-end=\"1534\">Types of books</strong></p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\"> </p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\">rare books {on a high shelf}</p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\"> </p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\">children’s books {in a specially designed space}</p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\"> </p>\n<p data-section-id=\"1mdpmta\" data-start=\"1512\" data-end=\"1534\">unwanted books {near the entrance}</p>\n<p data-start=\"1536\" data-end=\"1686\"> </p>\n<p data-start=\"1536\" data-end=\"1686\">requested books {at the back of the shop}</p>\n<p data-start=\"1536\" data-end=\"1686\"> </p>\n<p data-start=\"1536\" data-end=\"1686\">coursebooks {within the café}</p>", "answerOptions": [{"optionText": "near the entrance"}, {"optionText": "in the attic"}, {"optionText": "at the back of the shop"}, {"optionText": "on a high shelf"}, {"optionText": "near the stairs"}, {"optionText": "in a specially designed space"}, {"optionText": "within the café"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('6c2882d3-00dc-42d5-a45a-c5c226631895', '0c07d4b3-d0fc-4a08-8c9b-7ef9ffd7975e', 'matching', ' Questions 14-19', NULL, '<p>Reading Passage 2 has six paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, i-viii, in boxes 14-19.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Objectives of the regeneration project"}, {"optionText": "ii Architectural details of the station buildings"}, {"optionText": "iii Features and facilities of the completed development"}, {"optionText": "iv The remains of a railway system"}, {"optionText": "v A positive evaluation of the finished project"}, {"optionText": "vi A way of controlling development costs"}, {"optionText": "vii Ways of crossing the site"}, {"optionText": "viii Reasons why the area had become neglected"}], "matchingItems": null}', 'null', '[{"content": "<h4 data-path-to-node=\"4\">14. Paragraph 1</h4>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>iv. The remains of a railway system</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Đoạn này mô tả vị trí, hình dạng tam giác (<em>triangular-shaped area</em>) và nguồn gốc của Gleisdreieck, là nơi giao nhau của các <strong>tuyến đường sắt</strong> (<em>intersection of different railway lines</em>) và có các nhà ga, nhà kho thuộc về hệ thống đường sắt cũ.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn văn tập trung vào việc mô tả khu vực như là phần <strong>còn lại của một hệ thống đường sắt</strong>.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"7\">15. Paragraph 2</h4>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>viii. Reasons why the area had become neglected</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) Đoạn này giải thích tại sao khu vực bị bỏ hoang (<em>run down and abandoned</em>): hệ thống đường sắt ngừng hoạt động (<em>ceased to be used</em>), bị dùng làm bãi rác (<em>rubbish tip</em>), và nằm gần Bức tường Berlin (<em>closeness of the wall</em>) khiến nó trở thành vùng đất vô chủ (<em>no-man’s-land</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đoạn văn liệt kê các <strong>lý do khiến khu vực bị bỏ bê</strong> và suy tàn.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"10\">16. Paragraph 3</h4>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>i. Objectives of the regeneration project</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Đoạn này đề cập đến đề xuất của Nhà nước Berlin nhằm chuyển đổi Gleisdreieck thành một <strong>công viên đô thị lớn</strong> (<em>large urban park</em>), với mục tiêu tích hợp các khu vực đô thị khác nhau và phát triển các tiện ích mới.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn văn trình bày <strong>mục tiêu của dự án tái tạo</strong> khu đô thị.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"13\">17. Paragraph 4</h4>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>vii. Ways of crossing the site</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) Đoạn này mô tả cách khu vực được tổ chức xung quanh một đồng cỏ trung tâm, được cắt ngang bởi một <strong>lối đi bằng bê tông</strong> (<em>concrete footpath</em>) và một <strong>cặp đường ray</strong> (<em>pair of railway lines</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn văn tập trung vào <strong>các cách thức đi qua</strong> (<em>crossing</em>) khu đất, bao gồm đường ray, lối đi bộ và cầu thang bắc qua chênh lệch độ cao.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"16\">18. Paragraph 5</h4>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>iii. Features and facilities of the completed development</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) Đoạn này liệt kê chi tiết các thành phần của công viên: sân hiên nắng (<em>sunny terrace</em>), rừng cây, xích đu (<em>swings</em>), nhà trẻ (<em>nursery</em>), sân thể thao (<em>sports fields</em>), bề mặt cho ván trượt (<em>skateboards</em>), và vườn cộng đồng (<em>community gardens</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Đoạn văn mô tả <strong>các đặc điểm và tiện ích</strong> (<em>features and facilities</em>) đã hoàn thành của công viên.</p>\n</li>\n</ul>\n<h4 data-path-to-node=\"19\">19. Paragraph 6</h4>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>v. A positive evaluation of the finished project</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) Đoạn này bắt đầu bằng việc công viên được mở cửa và kết thúc bằng nhận định tích cực: “trái tim Berlin hiện có <strong>một lá phổi xanh mới</strong> (<em>new green lung</em>)” và đã bảo tồn được tinh thần của khu vực trước đây.</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Đoạn văn đưa ra <strong>đánh giá tích cực</strong> (<em>positive evaluation</em>) về dự án đã hoàn thành.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('8b0cda87-f219-47b2-85c0-ef05068f847b', '17f083a4-c2c5-49fa-ad24-d014daf2ce98', 'matching', 'Questions 17–20', '', '<p>Choose <strong>FOUR </strong>correct answers, <strong>A-F</strong></p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "A fertilisers"}, {"optionText": "B cooking lessons"}, {"optionText": "C advice on soil"}, {"optionText": "D eat-to-keep-fit course"}, {"optionText": "E use of a greenhouse"}, {"optionText": "F market stalls"}], "matchingItems": [{"questionPart": "city hospital ", "correctAnswer": "B"}, {"questionPart": "local government ", "correctAnswer": "E"}, {"questionPart": "university ", "correctAnswer": "C"}, {"questionPart": "supermarket ", "correctAnswer": "D"}]}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('3a7a1680-75c0-4b4a-9bcf-d272955e2cbc', '284ceef3-1b2f-4733-a4e6-72e04bc90dc1', 'matrix', 'Questions 14–19', '', '<p><span class="citation-11980 citation-11981 citation-end-11981">Which section contains the following information?</span></p>
<p><span class="citation-11978 citation-11979">Write the correct letter, </span><strong data-path-to-node="24" data-index-in-node="121"><span class="citation-11978 citation-11979">A–H</span></strong><span class="citation-11978 citation-11979 citation-end-11979">, in boxes 14–19 on your answer she</span><span class="citation-11978 citation-end-11978">et.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Two things at which leaf-cutter ants have succeeded but humans have failed.", "correctCategoryLetter": "H"}, {"itemText": "A comparison between the nests of leaf-cutter ants and lower attine ants.", "correctCategoryLetter": "C"}, {"itemText": "An assessment of the impact leaf-cutter ants have on their environment.", "correctCategoryLetter": "B"}, {"itemText": "The effect Escovopsis has on ant communities.", "correctCategoryLetter": "F"}, {"itemText": "The advantage for lower attine ants of growing a range of fungi.", "correctCategoryLetter": "G"}, {"itemText": "The discovery of the age of the attine-ant fungi.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Two things at which leaf-cutter ants have succeeded but humans have failed. — {H}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Astoundingly, the leaf-cutter ants are accomplishing <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"65\">feats beyond the power of humans</strong>: they are growing a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"118\">monocultural crop</strong> year after year without disaster, and they are using an <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"192\">antibiotic</strong>… so wisely that… they are not provoking antibiotic resistance…” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai việc kiến làm tốt hơn người là: canh tác độc canh bền vững và sử dụng kháng sinh mà không bị kháng thuốc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A comparison between the nests of leaf-cutter ants and lower attine ants. — {C}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The leaf-cutters use fresh vegetation; the other groups, known as the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"82\">lower attines because their nests are smaller and their techniques more primitive</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh trực tiếp kích thước tổ và kỹ thuật giữa hai nhóm kiến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. An assessment of the impact leaf-cutter ants have on their environment. — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Biologists believe <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"31\">15 percent of the leaf production of tropical forests disappears</strong> down the nests of leaf-cutter ants.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số 15% sản lượng lá rừng bị tiêu thụ chính là đánh giá về tác động môi trường của loài kiến này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. The effect Escovopsis has on ant communities. — {F}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…can <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"19\">devastate a fungus garden</strong> in a couple of days… other ants won’t go near it and the ants associated with the garden just <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"141\">starve to death</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác động của nấm Escovopsis là phá hủy vườn nấm và khiến đàn kiến chết đói.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. The advantage for lower attine ants of growing a range of fungi. — {G}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…possible reason for the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"39\">different varieties of fungus</strong> in the lower attine mushroom gardens to <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"109\">stay one step ahead of the relentless Escovopsis</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lợi thế của việc trồng nhiều loại nấm là giúp chúng luôn đi trước một bước trước sự tấn công của ký sinh trùng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. The discovery of the age of the attine-ant fungi. — {D}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…found that the leaf-cutters’ fungus was descended from a single pure strain, propagated for <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"107\">at least 23 million years</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số 23 triệu năm chính là tuổi thọ (age) của dòng nấm này.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('6760ad3f-689d-4f36-b88c-b028048055ef', '0ed2539e-aa7d-4760-a637-36285ec31e72', 'radio', 'Questions 1–6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information. <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the cultivation of olives, a period without rain is advantageous."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The most fertile fields are usually chosen for growing olives."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In ancient Greece, the olive tree was said to have divine origins."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Olive oil was more costly to buy in Greece than gold."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Plato mentions the use of olive oil in the preparation of food."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "North African farmers initially resisted the introduction of olive trees."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p><strong>1. In the cultivation of olives, a period without rain is advantageous.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “They actually <strong>produce better when subjected to these stressful conditions</strong>, and as a result, olive trees have traditionally been grown on land where little else will survive.”</li>\n<li><strong>Giải thích:</strong> Cây olive cho quả tốt hơn trong điều kiện căng thẳng (stressful conditions), bao gồm điều kiện <strong>khô hạn</strong> (dry conditions – thiếu mưa) được đề cập trước đó.</li>\n</ul>\n<p><strong>2. The most fertile fields are usually chosen for growing olives.</strong></p>\n<ul>\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “…olive trees have traditionally been grown on <strong>land where little else will survive</strong>.”</li>\n<li><strong>Giải thích:</strong> Cây olive được trồng ở đất xấu, nơi ít loài cây khác sống được, mâu thuẫn với việc chọn ruộng màu mỡ (most fertile fields).</li>\n</ul>\n<p><strong>3. In ancient Greece, the olive tree was said to have divine origins.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “The ancient Greeks believed the olive tree was a <strong>priceless gift from the goddess Athena</strong>…”</li>\n<li><strong>Giải thích:</strong> Món quà từ nữ thần Athena (divine origins) là minh chứng cho nguồn gốc thần thánh.</li>\n</ul>\n<p><strong>4. Olive oil was more costly to buy in Greece than gold.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…the Greek poet Homer called olive oil <strong>‘liquid gold’</strong>…”</li>\n<li><strong>Giải thích:</strong> Homer gọi dầu olive là “vàng lỏng” chỉ là một phép ẩn dụ để ca ngợi giá trị, <strong>không có sự so sánh</strong> về giá cả thực tế.</li>\n</ul>\n<p><strong>5. Plato mentions the use of olive oil in the preparation of food.</strong></p>\n<ul>\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “<strong>Its employment in cooking dates at least as far back as the 5th century BC, as described by the Greek philosopher Plato</strong>.”</li>\n<li><strong>Giải thích:</strong> Plato mô tả việc sử dụng dầu olive trong nấu ăn (preparation of food).</li>\n</ul>\n<p><strong>6. North African farmers initially resisted the introduction of olive trees.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “…olive trees were taken to <strong>North Africa and then to Spain</strong>…”</li>\n<li><strong>Giải thích:</strong> Có thông tin về việc đưa cây olive đến Bắc Phi, nhưng <strong>không có thông tin</strong> về phản ứng hay sự chống đối (resisted) của nông dân địa phương.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5872e24e-30c0-4cbc-aa22-10018222f1b8', 'e2a21ba6-d8f3-45b6-9f21-2cde1a341c35', 'fillup', 'Questions 31-40', '<p data-section-id="1czhe16" data-start="75" data-end="93"><span style="font-size: 12pt;">Write <strong>ONE WORD AND/OR A NUMBER </strong>for each answer.</span></p>
<p data-section-id="1czhe16" data-start="75" data-end="93"><span style="font-size: 12pt;"><strong>Tree planting</strong></span></p>
<p data-start="95" data-end="125"><strong>Reforestation projects should:</strong></p>
<p data-start="127" data-end="160">include a range of tree species</p>
<p data-start="162" data-end="246">not include invasive species because of possible {competition} with native species</p>
<p data-start="248" data-end="355">aim to capture carbon, protect the environment and provide sustainable sources of {food} for local people</p>
<p data-start="357" data-end="458">use tree seeds with a high genetic diversity to increase resistance to {disease} and climate change</p>
<p data-start="460" data-end="584">plant trees on previously forested land which is in a bad condition, not select land which is being used for {agriculture}</p>
<p data-section-id="1rpvynd" data-start="591" data-end="631"><strong>Large-scale reforestation projects</strong></p>
<p data-start="633" data-end="694">Base planning decisions on information from accurate {maps}</p>
<p data-start="696" data-end="808">Drones are useful for identifying areas in Brazil which are endangered by keeping {cattle} and illegal logging</p>
<p data-section-id="12kqc3l" data-start="815" data-end="856"><strong>Lampang Province, Northern Thailand</strong></p>
<p data-start="858" data-end="911">A forest was restored in an area damaged by mining.</p>
<p data-start="913" data-end="981">A variety of native fig trees were planted, which are important for:</p>
<p data-start="983" data-end="1017">supporting many wildlife species</p>
<p data-start="1019" data-end="1135">increasing the {speed} of recovery by attracting animals and birds, e.g. {monkeys} were soon attracted to the area</p>
<p data-section-id="hmkbne" data-start="1142" data-end="1175"><strong> Involving local communities</strong></p>
<p data-start="1177" data-end="1285">Destruction of mangrove forests in Madagascar made it difficult for people to make a living from {fishing}</p>
<p data-start="1287" data-end="1322">The mangrove reforestation project:</p>
<p data-start="1324" data-end="1362">provided employment for local people</p>
<p data-start="1364" data-end="1394">restored a healthy ecosystem</p>
<p data-start="1396" data-end="1444">protects against the higher risk of {flooding}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"162\" data-end=\"591\">Tree planting now dominates political and popular agendas and is often presented as an easy answer to the climate crisis, as well as a way for business corporations to offset their carbon emissions. But unfortunately, tree planting isn’t as straightforward as some people think. When the wrong trees are planted in the wrong place, it can do considerably more damage than good, failing to help either people or the environment.</p>\n<p data-start=\"593\" data-end=\"1156\">Reforestation projects are currently being undertaken on a huge scale in many countries and it’s crucial that the right trees are selected. A mix of species should be planted, typical of the local natural forest ecosystem and including rare and endangered species in order to create a rich ecosystem. It’s important to avoid non-native species that could become invasive. <span style=\"background-color: #f1c40f;\"><strong>(31) Invasive species are a significant contributor to the current global biodiversity crisis and are often in competition with native species</strong></span> and may threaten their long-term survival.</p>\n<p data-start=\"1158\" data-end=\"1692\">Restoring biodiversity that will maximise carbon capture is key when reforesting an area, but ideally any reforestation project should have several goals. These could include selecting trees that can contribute to wildlife conservation, <span style=\"background-color: #f1c40f;\"><strong>(32) improve the availability of food for the local community</strong> </span>and maintain the stability of soil systems. Meeting as many of these goals as possible, whilst doing no harm to local communities, native ecosystems and vulnerable species, is the sign of a highly successful tree-planting scheme.</p>\n<p data-start=\"1694\" data-end=\"2096\">To ensure the survival and resilience of a planted forest, it’s vital to use tree seeds with appropriate levels of genetic diversity: the amount of genetic variation found within a species essential for their survival. <strong><span style=\"background-color: #f1c40f;\">(33) Using seeds with low genetic diversity generally lowers the resilience of restored forests, which can make them vulnerable to disease and unable to adapt to climate change.</span></strong></p>\n<p data-start=\"2098\" data-end=\"2730\">Choosing the right location for reforestation projects is as important as choosing the right trees. Ultimately, the best area for planting trees would be in formerly forested areas that are now deforested. It’s better to avoid non-forested landscapes such as natural grasslands, savannas or wetlands as these ecosystems already contribute greatly to capturing carbon. It would also be advantageous to choose an area where trees could provide other benefits, such as recreational spaces. <strong><span style=\"background-color: #f1c40f;\">(34) Reforesting areas which are currently exploited for agriculture should be avoided as this often leads to other areas being deforested</span></strong>.</p>\n<p data-start=\"2732\" data-end=\"3280\">Large-scale reforestation projects require careful planning. Making the right decisions about where to plant trees depends on having the right information. <span style=\"background-color: #f1c40f;\"><strong>(35) Having detailed and up-to-date maps identifying high-priority areas for intervention is essential</strong></span>. Drone technology is a useful tool in helping to prioritise and monitor areas of degraded forest for restoration. In Brazil, it’s being used to identify and quantify how <strong><span style=\"background-color: #f1c40f;\">(36) parts of the Amazon are being devastated by human activities such as rearing cattle and illegal logging</span></strong>.</p>\n<p data-start=\"3282\" data-end=\"4331\">A good example of where the right trees were picked to achieve a restored forest is in Lampang Province in Northern Thailand. A previously forested site which had been degraded through mining was reforested by a cement company together with Chiang Mai University. After spreading 60 cm of topsoil, they planted 14 different native tree species which included several species of fig. Figs are a keystone species because of the critical role they play in maintaining wildlife populations. <span style=\"background-color: #f1c40f;\"><strong>(37) They are central to tropical reforestation projects as they accelerate the speed of the recovery process by attracting animals and birds which act as natural seed dispersers</strong></span>. This helps to promote diversity through the healthy regrowth of a wide range of plant species. Unlike the majority of fruit trees, figs bear fruit all year round, providing a reliable food source for many species. <span style=\"background-color: #f1c40f;\"><strong>(38) At this site, for example, after only three rainy seasons, monkeys started visiting to eat the fig fruits</strong></span>, naturally dispersing seeds through defecation.</p>\n<p data-start=\"4333\" data-end=\"4470\">Reforestation projects should always aim to make sure that local communities are consulted and involved in the decision-making process.</p>\n<p data-start=\"4472\" data-end=\"5393\">The restoration of mangrove forests in Madagascar is an example of a project which has succeeded in creating real benefits for the community. <strong><span style=\"background-color: #f1c40f;\">(39) Destruction of the mangrove forests had a terrible impact on plant and animal life, and also badly affected the fishing industry, which was a major source of employment for local people living in coastal areas. The reforestation project involved hiring local people</span></strong> to plant and care for the new mangrove trees. Millions of mangrove trees have now been planted which has resulted in the return of a healthy aquatic ecosystem. <strong><span style=\"background-color: #f1c40f;\">(40) The mangroves also act as a defence against the increased threat of flooding</span></strong> caused by climate change. What’s more, the local economy is more stable and thousands more Madagascans are now able to send their children to school. When soil becomes impoverished, not only ecosystems but also the whole of society are negatively impacted.</p>"}]', 0);
INSERT INTO public.questions VALUES ('21529e2a-66bf-4a2f-920b-b0b3b61c783a', '0c07d4b3-d0fc-4a08-8c9b-7ef9ffd7975e', 'checkbox', 'Questions 20-21', NULL, '<p>Choose <strong>TWO </strong>correct answers.<br />
Which <strong>TWO </strong>reasons are given for the choice of Gleisdreieck as a site for a park?</p>
', 'multiple_choice_many', 'null', '[{"option": "It was a habitat for some rare wildlife species.", "correct": false}, {"option": "It contained a particular tourist attraction.", "correct": true}, {"option": "It lay at the heart of the reunited city.", "correct": true}, {"option": "It was served by a major rail network.", "correct": false}, {"option": "It contained buildings which could be easily converted.", "correct": false}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"6\">20. It lay at the heart of the reunited city.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>(Được chọn)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “More importantly, the <strong>unification of the formerly divided city gave the zone more centrality</strong>, at which point it became imperative to identify a purpose for it.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Sự thống nhất (<em>unification</em>) đã mang lại <strong>vị trí trung tâm hơn</strong> (<em>more centrality</em>) cho khu vực, khiến việc quy hoạch nó trở nên bắt buộc và là lý do then chốt để chọn nó cho dự án tái phát triển lớn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">21. It contained a particular tourist attraction.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>(Được chọn)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “Shortly before the fall of the Berlin Wall, however, the <strong>German Museum of Technology was established there, attracting large numbers of visitors and giving visibility to the site</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Việc <strong>Bảo tàng Công nghệ Đức</strong> (<em>German Museum of Technology</em>) đã được thành lập tại đó đã thu hút du khách (<em>attracting large numbers of visitors</em>) và tăng khả năng hiển thị (<em>visibility</em>), khiến nó trở thành một điểm thu hút du lịch cụ thể và là yếu tố quan trọng khi xem xét mục đích sử dụng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('328ffd5e-c9f3-406d-a9ea-035c22b14e1a', '284ceef3-1b2f-4733-a4e6-72e04bc90dc1', 'matrix', 'Questions 20–24', '', '<p>Classify the following descriptions as relating to</p>
<p data-path-to-node="29">Write the correct letter, <strong data-path-to-node="29" data-index-in-node="26">A, B or C</strong>, in boxes 20–24 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "the use of dead vegetation to cultivate their fungus", "correctCategoryLetter": "B"}, {"itemText": "very small ants that keep the fungus free of foreign organisms", "correctCategoryLetter": "A"}, {"itemText": "the ability to safely eat harmful plants", "correctCategoryLetter": "C"}, {"itemText": "the cultivation of a single fungus", "correctCategoryLetter": "A"}, {"itemText": "a nest with a very large number of rooms for growing fungus", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Leaf-cutting ants", "categoryLetter": "A"}, {"categoryText": "Lower attines", "categoryLetter": "B"}, {"categoryText": "Both leaf-cutting ants and lower attine ants", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. The use of dead vegetation to cultivate their fungus — {B: Lower attines}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the other groups [lower attines]… feed their gardens with <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"75\">similar leaves that have fallen on the ground and insects that lie on the forest floor</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lá rụng và côn trùng chết trên nền rừng chính là thực vật chết (dead vegetation).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. Very small ants that keep the fungus free of foreign organisms — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…<strong data-path-to-node=\"21,0,0\" data-index-in-node=\"15\">leaf-cutter worker ants come in made-to-fit sizes</strong>… and <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"72\">miniature workers</strong> to seed them with fungus and <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"119\">clean off alien growths</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ nhóm Leaf-cutter mới được mô tả là có sự phân hóa kích thước thợ, trong đó kiến thợ nhỏ (miniature) làm nhiệm vụ dọn dẹp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. The ability to safely eat harmful plants — {C: Both}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"16\">attine ants’ achievement</strong> is remarkable because it allows them to consume… harvest of tropical forests whose <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"126\">leaves are laden with poisonous chemicals</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cả bộ tộc kiến Attine (bao gồm cả leaf-cutters và lower attines) đều có khả năng này nhờ sự tiêu hóa của nấm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">23. The cultivation of a single fungus — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"16\">pure strain</strong> of fungus grown by the <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"51\">leaf-cutters</strong>…” (Đoạn E) và “…the <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"88\">pure clone cultivation of the leaf-cutters</strong>…” (Đoạn D).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">24. A nest with a very large number of rooms for growing fungus — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “A <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"14\">single leaf-cutter nest</strong> may contain a <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"52\">thousand such chambers</strong>…” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ tổ của kiến leaf-cutter mới được mô tả là có quy mô khổng lồ với hàng nghìn ngăn (rooms/chambers).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('51c5ae82-1312-47cb-b043-e40c71a556c3', '3b5ad871-0bc3-48f5-9084-28c192a2f16f', 'matrix', 'Questions 27 – 32', '', '<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, <strong data-path-to-node="11" data-index-in-node="139">A-F</strong>, in boxes 27-32 on your answer sheet.</p>
<p><strong>NB You may use any letter more than once.</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "disagreement with the view that employing talented people enables companies to achieve top performance", "correctCategoryLetter": "A"}, {"itemText": "a description of what individuals have to do on a regular basis to improve their performance", "correctCategoryLetter": "E"}, {"itemText": "the evidence that exceptional talent exists in all areas of life", "correctCategoryLetter": "B"}, {"itemText": "how different ways of evaluating achievement at work can cause different reactions in employees", "correctCategoryLetter": "F"}, {"itemText": "the belief that the time when an assessment is carried out affects its accuracy", "correctCategoryLetter": "C"}, {"itemText": "the extent to which different talented individuals have contributed to their particular area of achievement", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Disagreement with the view that employing talented people enables companies to achieve top performance — {A}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “This idea, that… those firms with the best people do the best – is both <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"86\">flawed and harmful</strong> to people and organisations.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp bày tỏ sự không đồng tình (disagreement) với quan niệm rằng cứ có người giỏi nhất là công ty sẽ hoạt động tốt nhất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. A description of what individuals have to do on a regular basis to improve their performance — {E}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…exceptional performance doesn’t happen without around <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"69\">ten years of nearly daily, deliberate practice for about four hours a day</strong>…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E mô tả chi tiết những gì cá nhân cần làm hàng ngày (luyện tập có chủ đích trong 10 năm) để cải thiện và đạt được hiệu suất xuất sắc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. The evidence that exceptional talent exists in all areas of life — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “There is no question that in <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"41\">every field, from sports to computer programming to music</strong>, there are people who are better than the rest.” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. How different ways of evaluating achievement at work can cause different reactions in employees — {F}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Dweck identified two sets of goals… <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"50\">performance goals</strong>… prone to helpless behaviour… and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">learning goals</strong>… strive for higher performance.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F phân tích cách đánh giá dựa trên “mục tiêu hiệu suất” hoặc “mục tiêu học hỏi” dẫn đến những phản ứng (reactions) khác nhau của nhân viên sau thất bại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. The belief that the time when an assessment is carried out affects its accuracy — {C}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“If performance naturally varies, any <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"49\">measurement taken at a single point in time</strong>, such as when someone is being hired, will have <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"141\">error and imprecision</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả lập luận rằng vì phong độ con người luôn thay đổi, nên việc đánh giá tại một thời điểm duy nhất (ví dụ lúc tuyển dụng) sẽ dẫn đến sự thiếu chính xác và sai lệch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. The extent to which different talented individuals have contributed to their particular area of achievement — {B}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…in music, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"25\">16 individuals have produced about 50 per cent</strong> of the Western classical music… while another <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"120\">235 composers have produced the remaining half</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là số liệu cụ thể về mức độ đóng góp (extent of contribution) của các cá nhân ngôi sao so với phần còn lại.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('0514669d-af86-45a4-a7ef-2386590c1e31', '3b5ad871-0bc3-48f5-9084-28c192a2f16f', 'fillup', 'Questions 33 – 35', '<p>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>from the passage for each answer.</p>
<p>How many Western classical composers are identified as exceptionally talented?{16| 16 individuals}</p>
<p>Which composer initially received little recognition for his work?{Sebastian Bach| Bach}</p>
<p>Who can help improve the performance of people practising daily?{coaches }</p>', '', 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. How many Western classical composers are identified as exceptionally talented? — {16 / 16 individuals}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in music, <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"25\">16 individuals</strong> have produced about 50 per cent of the Western classical music…” (Đoạn B).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. Which composer initially received little recognition for his work? — {Bach / Sebastian Bach}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It should surprise no-one that for <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"47\">Bach</strong> to be considered a great musician, standards of music <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"106\">needed to change</strong> to embrace the qualities that his compositions possessed.” (Đoạn C).</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Điều này ngụ ý ban đầu ông chưa được coi là vĩ đại cho đến khi tiêu chuẩn âm nhạc thay đổi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. Who can help improve the performance of people practising daily? — {coaches}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…with the assistance of their <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"44\">coaches</strong>, have access to the best techniques.” (Đoạn E).</p>\n</li>\n</ul>"}]', 1);
